import { useState } from "react";
function Forgot() {
    let [emailinput, changeemailinput] = useState("");
    function func1() {
        alert("If an account with the provided email exists, a password reset link has been sent.")
    }
    function sendemail() {
        changeemailinput(document.querySelector("input").value);
    }
    return<>
    <div>
        <h1>Forgot password?</h1>
        <p>Enter email here:</p>
        <input onChange={() => sendemail()} type="text" placeholder="Email" />
        <button onClick={() => func1()}>Submit</button>
    </div>
        
    </>
}
export default Forgot;
